// Extract ticket data from Zammad webhook payload
const ticket = $input.first().json.body?.ticket || $input.first().json.ticket;
if (!ticket) {
  throw new Error('No ticket data in webhook payload');
}

const customer = ticket.customer || {};
const article = ticket.article || {};

// Build normalized ticket object
return [{
  json: {
    ticket_id: ticket.id,
    ticket_number: ticket.number,
    title: ticket.title,
    state: ticket.state?.name || ticket.state || 'new',
    priority: ticket.priority?.name || ticket.priority || 'normal',
    group: ticket.group?.name || ticket.group || 'Users',
    customer_email: customer.email || '',
    customer_name: [customer.firstname, customer.lastname].filter(Boolean).join(' ') || customer.email || 'Unknown',
    article_body: article.body || '',
    created_at: ticket.created_at,
    updated_at: ticket.updated_at,
    zammad_url: `https://helpdesk.aiqso.io/#ticket/zoom/${ticket.id}`
  }
}];

